// catalog/domain/catalog-product.entity.ts
import { Entity, ProductId, Money } from '@shopflow/shared-kernel';export type ProductStatus = 'active' | 'archived' | 'draft';export interface ProductVariant {
readonly variantId: string;
readonly sku: string;
readonly attributes: Record<string, string>; // { color: 'Blue', size: 'L' }
readonly price: Money;
readonly stockCount: number;
}export class CatalogProduct extends Entity<ProductId> {
private _name: string;
private _description: string;
private _status: ProductStatus;
private _variants: ProductVariant[];
private _imageUrls: string[]; constructor(
id: ProductId,
name: string,
description: string,
status: ProductStatus,
variants: ProductVariant[],
imageUrls: string[],
) {
super(id);
this.validateName(name);
this.validateVariants(variants);
this._name = name;
this._description = description;
this._status = status;
this._variants = [...variants];
this._imageUrls = [...imageUrls];
} // Read accessors
get name(): string { return this._name; }
get description(): string { return this._description; }
get status(): ProductStatus { return this._status; }
get variants(): readonly ProductVariant[] { return this._variants; }
get imageUrls(): readonly string[] { return this._imageUrls; } // Computed domain properties
get isActive(): boolean { return this._status === 'active'; }
get isAvailable(): boolean {
return this.isActive && this._variants.some(v => v.stockCount > 0);
} get lowestPrice(): Money | null {
if (this._variants.length === 0) return null;
return this._variants.reduce((lowest, v) =>
v.price.isLessThan(lowest) ? v.price : lowest,
this._variants[0].price
);
} get primaryImageUrl(): string | null {
return this._imageUrls[0] ?? null;
} // Domain methods — mutations return new state or throw
updateName(newName: string): void {
this.validateName(newName);
this._name = newName;
} findVariantById(variantId: string): ProductVariant | undefined {
return this._variants.find(v => v.variantId === variantId);
} isVariantInStock(variantId: string): boolean {
const variant = this.findVariantById(variantId);
return !!variant && variant.stockCount > 0;
} private validateName(name: string): void {
if (!name || name.trim().length < 2) {
throw new Error('Product name must be at least 2 characters');
}
if (name.length > 200) {
throw new Error('Product name cannot exceed 200 characters');
}
} private validateVariants(variants: ProductVariant[]): void {
if (variants.length === 0) {
throw new Error('A product must have at least one variant');
}
}
