updateQuantity$ = createEffect(() =>
this.actions$.pipe(
ofType(CartActions.quantityUpdated),
// Optimistic: update state immediately
tap(({ cartItemId, newQuantity }) =>
this.store.dispatch(CartActions.quantityUpdatedOptimistically({
cartItemId, newQuantity
}))
