// Then sync with server
switchMap(({ cartItemId, newQuantity }) =>
this.cartRepository.updateItemQuantity(cartItemId, newQuantity).pipe(
map(() => CartActions.quantityUpdateConfirmed({ cartItemId })),
catchError(() => of(CartActions.quantityUpdateRolledBack({ cartItemId })))
)
)
