Article 5: Aggregates & Aggregate Roots
The Problem: Business Rules Without Enforcement
Consider ShopFlow’s cart. Business rules say:

• You can’t have more than 10 of the same item

• You can’t check out with an empty cart

• A coupon can only be applied once

• The total discount from coupons cannot exceed the cart subtotal
Where do these rules live? In your codebase today, probably scattered across:

• A component’s addToCart() handler

• A service method

• A backend validation error that you catch and display
An Aggregate centralizes these rules in one place and makes them impossible to bypass.
The Cart Aggregate
The Cart is the central aggregate in ShopFlow. It is the Aggregate Root — the only public entry point for modifying cart state.
typescript
// cart/domain/cart.aggregate.ts
import { Entity, CartId, ProductId, CartItemId, Money, Quantity } from '@shopflow/shared-kernel';
import { CartItem } from './cart-item.entity';
import { Coupon } from './coupon.value-object';export type CartStatus = 'open' | 'checked_out' | 'abandoned';interface CartProps {
id: CartId;
customerId: string;
status: CartStatus;
items: CartItem[];
appliedCoupon: Coupon | null;
currency: 'EUR' | 'USD' | 'GBP';
}// Domain Events (covered fully in Article 7)
export interface CartItemAddedEvent {
type: 'CartItemAdded';
cartId: string;
productId: string;
quantity: number;
}export interface CartCheckedOutEvent {
type: 'CartCheckedOut';
cartId: string;
total: { amountInMinorUnits: number; currency: string };
}export type CartDomainEvent = CartItemAddedEvent | CartCheckedOutEvent;export class Cart extends Entity<CartId> {
private _items: CartItem[];
private _appliedCoupon: Coupon | null;
private _status: CartStatus;
private readonly _customerId: string;
private readonly _currency: 'EUR' | 'USD' | 'GBP';
private _domainEvents: CartDomainEvent[] = []; private static readonly MAX_QUANTITY_PER_ITEM = 10;
private static readonly MAX_DISTINCT_ITEMS = 50; constructor(props: CartProps) {
super(props.id);
this._items = [...props.items];
this._appliedCoupon = props.appliedCoupon;
this._status = props.status;
this._customerId = props.customerId;
this._currency = props.currency;
} // --- Read accessors ---
get items(): readonly CartItem[] { return this._items; }
get appliedCoupon(): Coupon | null { return this._appliedCoupon; }
get status(): CartStatus { return this._status; }
get customerId(): string { return this._customerId; }
get isEmpty(): boolean { return this._items.length === 0; } // --- Computed values ---
get subtotal(): Money {
return this._items.reduce(
(total, item) => total.add(item.lineTotal),
Money.zero(this._currency)
);
} get discount(): Money {
if (!this._appliedCoupon) return Money.zero(this._currency);
return this._appliedCoupon.calculateDiscount(this.subtotal);
} get total(): Money {
const subtotal = this.subtotal;
const disc = this.discount;
return disc.isGreaterThan(subtotal)
? Money.zero(this._currency)
: subtotal.subtract(disc);
} get itemCount(): number {
return this._items.reduce((count, item) => count + item.quantity.value, 0);
} // --- Domain Commands (Aggregate Root enforces invariants) --- addItem(
itemId: CartItemId,
productId: ProductId,
productName: string,
variantId: string,
unitPrice: Money,
requestedQuantity: Quantity,
): void {
this.assertIsOpen(); const existingItem = this.findItemByProduct(productId, variantId); if (existingItem) {
const newQuantity = existingItem.quantity.value + requestedQuantity.value;
if (newQuantity > Cart.MAX_QUANTITY_PER_ITEM) {
throw new Error(
`Cannot exceed ${Cart.MAX_QUANTITY_PER_ITEM} of the same item in cart`
);
}
existingItem.updateQuantity(new Quantity(newQuantity));
} else {
if (this._items.length >= Cart.MAX_DISTINCT_ITEMS) {
throw new Error(
`Cart cannot contain more than ${Cart.MAX_DISTINCT_ITEMS} distinct items`
);
}
this._items.push(new CartItem(itemId, productId, productName, variantId, unitPrice, requestedQuantity));
} this._domainEvents.push({
type: 'CartItemAdded',
cartId: this.id.value,
productId: productId.value,
quantity: requestedQuantity.value,
});
} removeItem(cartItemId: CartItemId): void {
this.assertIsOpen();
const index = this._items.findIndex(item => item.id.equals(cartItemId));
if (index === -1) {
throw new Error(`Cart item not found: ${cartItemId.value}`);
}
this._items.splice(index, 1);
} updateItemQuantity(cartItemId: CartItemId, newQuantity: Quantity): void {
this.assertIsOpen();
const item = this._items.find(i => i.id.equals(cartItemId));
if (!item) throw new Error(`Cart item not found: ${cartItemId.value}`);
if (newQuantity.value > Cart.MAX_QUANTITY_PER_ITEM) {
throw new Error(`Quantity cannot exceed ${Cart.MAX_QUANTITY_PER_ITEM}`);
}
item.updateQuantity(newQuantity);
} applyCoupon(coupon: Coupon): void {
this.assertIsOpen();
if (this._appliedCoupon) {
throw new Error('A coupon is already applied. Remove it before applying a new one.');
}
if (!coupon.isValidFor(this.subtotal)) {
throw new Error(`Coupon "${coupon.code}" is not valid for this cart total`);
}
this._appliedCoupon = coupon;
} removeCoupon(): void {
this.assertIsOpen();
this._appliedCoupon = null;
} checkout(): void {
this.assertIsOpen();
if (this.isEmpty) {
throw new Error('Cannot check out an empty cart');
}
this._status = 'checked_out';
this._domainEvents.push({
type: 'CartCheckedOut',
cartId: this.id.value,
total: this.total.toJSON(),
});
} // Collect and clear domain events (for publishing after persistence)
pullDomainEvents(): CartDomainEvent[] {
const events = [...this._domainEvents];
this._domainEvents = [];
return events;
} // --- Private helpers ---
private assertIsOpen(): void {
if (this._status !== 'open') {
throw new Error(`Cannot modify a cart with status: ${this._status}`);
}
} private findItemByProduct(productId: ProductId, variantId: string): CartItem | undefined {
return this._items.find(
item => item.productId.equals(productId) && item.variantId === variantId
);
}
